class Solution {
public:
    string sortString(string s) {
        string res;
        priority_queue<char> maxHeap;
        priority_queue<char, vector<char>, greater<char>> minHeap;
        for (char c : s) {
            maxHeap.push(c);
            minHeap.push(c);
        }
        while (!maxHeap.empty() || !minHeap.empty()) {
            if (!maxHeap.empty()) {
                res += maxHeap.top();
                maxHeap.pop();
            }
            if (!minHeap.empty()) {
                res += minHeap.top();
                minHeap.pop();
            }
        }
        return res;
    }
};
```
